final:
module top_module(
  input clk,
  input reset,
  input enable,
  output reg [3:0] lfsr_out
);reg [3:0] invalid_lfsr;

always @(posedge clk) begin
  if (reset) begin
    invalid_lfsr <= 4'b0001;
  end else if (enable) begin
    invalid_lfsr <= {invalid_lfsr[2:0], invalid_lfsr[3] ^ invalid_lfsr[0]};
  end
end

assign lfsr_out = invalid_lfsr;

endmodule
